  val nums = Array_Long.map(_.toInt).toArray
  val n = nums.length
  var totalOperations: Long = 0

  def isPrime(n: Int): Boolean = {
    if (n <= 1) false
    else if (n <= 3) true
    else if (n % 2 == 0 || n % 3 == 0) false
    else {
      var i = 5
      while (i * i <= n) {
        if (n % i == 0 || n % (i + 2) == 0) return false
        i = i + 6
      }
      true
    }
  }

  def findMinSteps(n: Int, requiredCondition: Int => Boolean): Int = {
    var k = 0
    while (!requiredCondition(n + k)) {
      k += 1
    }
    k
  }

  for (i <- 0 until n) {
    val currentNum = nums(i)

    if (i % 2 == 0) {
      // Even index: Must be Prime
      val requiredCondition: Int => Boolean = (x: Int) => isPrime(x)
      val steps = findMinSteps(currentNum, requiredCondition)
      totalOperations += steps.toLong
    } else {
      // Odd index: Must be Non-Prime
      val requiredCondition: Int => Boolean = (x: Int) => !isPrime(x)
      val steps = findMinSteps(currentNum, requiredCondition)
      totalOperations += steps.toLong
    }
  }
  totalOperations
}
